export const ra1Questions = [
  { question: "¿Para qué usamos la notaciónO grandeen práctica?", options: [{ text: "Predecir segundos exactos de ejecución", isCorrect: false }, { text: "Describir el crecimiento de tiempo/espacio al aumentar la entrada", isCorrect: true }, { text: "Calibrar automáticamente el tamaño del clúster", isCorrect: false }, { text: "Elegir la librería más moderna", isCorrect: false }] , explanation: "O grande = ¿cómo escala esto cuando los datos crecen? No da segundos exactos, da la tendencia. O(N) vs O(N^2)." },
  { question: "En MapReduce, ¿qué parte suele dominar el coste y conviene atacar primero?", options: [{ text: "El mapeo por uso intensivo de CPU", isCorrect: false }, { text: "El shuffle de red y la ordenación", isCorrect: true }, { text: "El reduce por escribir el resultado", isCorrect: false }, { text: "La planificación del coordinador", isCorrect: false }] , explanation: "Shuffle = mover datos entre nodos por la red. La red es lenta. Ordenar es caro. Ahí está el mayor cuello de botella." },
  { question: "¿Para qué sirve uncombiner?", options: [{ text: "Balancear claves entre reducers", isCorrect: false }, { text: "Agregar localmente para enviar menos por red", isCorrect: true }, { text: "Fusionar salidas finales de reducers", isCorrect: false }, { text: "Reintentar tareas fallidas", isCorrect: false }] , explanation: "Combiner = mini-reduce en el mapper. Suma lo local antes de enviarlo por la red. Menos red = más rápido." },
  { question: "Si unaclave muy frecuenteatasca un reducer (skew), ¿qué técnica ayuda más?", options: [{ text: "Aumentar el tamaño de bloque en HDFS", isCorrect: false }, { text: "Subir el número de mappers", isCorrect: false }, { text: "Dividir la clave popular en subclaves (“salting”) y recombinar después", isCorrect: true }, { text: "Comprimir la salida final", isCorrect: false }] , explanation: "Salting = romper la clave gorda en cachos (ej: 'Madrid_1', 'Madrid_2') para repartir el trabajo entre varios reducers. Luego sumas el total." },
  { question: "Sobreescalarañadiendo máquinas, ¿qué afirmación es más acertada?", options: [{ text: "Si duplicas nodos, el tiempo siempre se parte por dos", isCorrect: false }, { text: "Más nodos no arreglan un mal algoritmo", isCorrect: true }, { text: "Con más CPU desaparece el coste de disco", isCorrect: false }, { text: "La red deja de importar a gran escala", isCorrect: false }] , explanation: "Algoritmo O(N^3) + 1000 nodos = sigue siendo inútil. Escalar añade hardware, pero no cambia la matemática del algoritmo." },
  { question: "En teoría de conjuntos aplicada a datos, unconjuntose entiende como…", options: [{ text: "Lista ordenada de filas con posibles duplicados", isCorrect: false }, { text: "Colección sin duplicados", isCorrect: true }, { text: "Muestra aleatoria dependiente del muestreo", isCorrect: false }, { text: "Fotograma exacto del DWH con todas las columnas", isCorrect: false }] , explanation: "Conjunto matemático = únicos. No hay orden, no hay repetidos. {1,2,2} es lo mismo que {1,2}." },
  { question: "La operación que captura “elementosen A y no en B” es…", options: [{ text: "Unión (A ∪ B)", isCorrect: false }, { text: "Intersección (A ∩ B)", isCorrect: false }, { text: "Diferencia (A − B)", isCorrect: true }, { text: "Complemento (A^c)", isCorrect: false }] , explanation: "Diferencia = lo que está en A pero quitando todo lo que también está en B. Elementos exclusivos de A." },
  { question: "La regla deinclusión–exclusiónpara dos conjuntos establece que…", options: [{ text: "|A∪B|=|A|+|B|+|A∩B| porque se cuentan coincidencias dos veces", isCorrect: false }, { text: "|A∪B|=|A|+|B|−|A∩B|", isCorrect: true }, { text: "No existe fórmula general; se calcula caso por caso", isCorrect: false }, { text: "|A∩B|=|A|−|B| si A⊆B", isCorrect: false }] , explanation: "Inclusión-exclusión: si sumas A y sumas B, la intersección la has contado dos veces. Tienes que restarla una vez para que cuadre." },
  { question: "Una equivalencia correcta deDe Morganes…", options: [{ text: "(A∪B)^c=A^c∪B^c", isCorrect: false }, { text: "(A∩B)^c = A^c ∪ B^c", isCorrect: true }, { text: "(A∩B)^c = A ∪ B", isCorrect: false }, { text: "(A∪B)^c = A ∩ B", isCorrect: false }] , explanation: "De Morgan: el complemento de la intersección es la unión de los complementos. Cambia el signo de dentro y dale la vuelta a la U/n." },
  { question: "Lacardinalidadde un conjunto, denotada |A|, significa…", options: [{ text: "Suma de frecuencias absolutas con repetición", isCorrect: false }, { text: "Número de únicos", isCorrect: true }, { text: "Volumen total de datos en disco", isCorrect: false }, { text: "Conteo ponderado por pesos de las claves", isCorrect: false }] , explanation: "Cardinalidad = cuántos elementos diferentes hay. |A|. Sin contar repetidos, claro, porque es un conjunto." },
  { question: "¿Cuándo elegirAPIfrente a scraping?", options: [{ text: "Cuando la página carga más rápido que la API", isCorrect: false }, { text: "Siempre, incluso si no cubre los campos necesarios", isCorrect: false }, { text: "Nunca; las APIs ocultan información por diseño", isCorrect: false }, { text: "Cuando hay API con datos y límites", isCorrect: true }] , explanation: "Si hay API, usa API. Es estructurado, oficial y más estable. Scraping es plan B cuando no hay API o la API esconde datos." },
  { question: "¿Qué implica uncontrol de límites responsableal extraer datos?", options: [{ text: "Ocultar el User-Agent para evitar bloqueos", isCorrect: false }, { text: "Subir la concurrencia para terminar antes", isCorrect: false }, { text: "Recargar en bucle hasta que responda", isCorrect: false }, { text: "Ritmo controlado, backoff en errores, identificación clara y registro de qué, cuándo y cómo se pidió", isCorrect: true }] , explanation: "Scraping responsable: no tumbes el servidor (ritmo), pausa si hay error (backoff), di quién eres (User-Agent real), y guarda evidencia." },
  { question: "¿Para qué sirven losselectores(CSS/XPath) en scraping?", options: [{ text: "Evitar usar APIs en cualquier caso", isCorrect: false }, { text: "Identificar el patrón repetido y extraer contenido estructurado", isCorrect: true }, { text: "Medir el tiempo de carga de la web", isCorrect: false }, { text: "Renderizar la página como un navegador", isCorrect: false }] , explanation: "Selector CSS/XPath = tu puntero láser. Le dices 'coge el texto de todos los <h2 class=\"precio\">'. Transforma HTML caótico en datos limpios." },
  { question: "Antebarreras anti-bot(CAPTCHA, rate-limit estricto), la respuesta responsable es…", options: [{ text: "Aumentar la frecuencia para “pasar rápido”", isCorrect: false }, { text: "Rotar IPs y headless hasta romper la barrera", isCorrect: false }, { text: "Parar, acotar el alcance o cambiar a una vía permitida (API/feed) y, si procede, pedir permiso", isCorrect: true }, { text: "Descargar todo de madrugada sin identificarte", isCorrect: false }] , explanation: "Si hay CAPTCHA, el sitio dice 'no robots'. Forzarlo rotando IPs es agresivo. Párate y busca vía oficial o pide permiso." },
  { question: "Para asegurartrazabilidadde una extracción, debes conservar…", options: [{ text: "Solo la tabla final ya limpia", isCorrect: false }, { text: "Los prints de consola de la última ejecución", isCorrect: false }, { text: "Respuesta cruda, URL/endpoint, parámetros y marca de tiempo de obtención", isCorrect: true }, { text: "Nada si el scraping fue rápido", isCorrect: false }] , explanation: "Trazabilidad = poder demostrar de dónde y cuándo sacaste el dato. Guarda el raw, la URL y la hora. Si no, tu dato no tiene origen creíble." },
  { question: "En un grafo dirigido, hayconectividad fuertecuando…", options: [{ text: "Hay camino si ignoramos la dirección de las aristas", isCorrect: false }, { text: "Todos los nodos tienen el mismo grado", isCorrect: false }, { text: "El grafo es acíclico", isCorrect: false }, { text: "Existe un camino dirigido de u a v y de v a u para todo par de nodos", isCorrect: true }] , explanation: "Conectividad fuerte = todos pueden llegar a todos, respetando las flechas. Como una ciudad donde puedes ir de cualquier barrio a cualquier otro." },
  { question: "UnDAGse caracteriza porque…", options: [{ text: "Tiene exactamente una fuente y un sumidero", isCorrect: false }, { text: "Admite ordenación topológica", isCorrect: true }, { text: "Todas las aristas pesan lo mismo", isCorrect: false }, { text: "Es conexo en sentido no dirigido", isCorrect: false }] , explanation: "DAG = Directed Acyclic Graph (sin ciclos). Si no hay ciclos, puedes ordenar las tareas de principio a fin sin dependencias circulares." },
  { question: "Un grafobipartitose define correctamente como…", options: [{ text: "Todo nodo tiene grado al menos dos", isCorrect: false }, { text: "Las aristas siempre llevan orientación", isCorrect: false }, { text: "V se divide en dos orillas A y B y E ⊆ A×B (solo hay aristas entre orillas distintas)", isCorrect: true }, { text: "Los ciclos están prohibidos", isCorrect: false }] , explanation: "Bipartito = dos bandos (ej: Usuarios y Películas). Solo hay conexiones cruzadas, nunca entre los del mismo bando." },
  { question: "En grafos ponderados con pesos ≥ 0, laruta más cortaentre dos nodos es la que…", options: [{ text: "Usa el menor número de aristas", isCorrect: false }, { text: "Maximiza el grado de los nodos intermedios", isCorrect: false }, { text: "Minimiza la suma acumulada de pesos a lo largo del camino", isCorrect: true }, { text: "Pasa por el mayor número de alternativas paralelas", isCorrect: false }] , explanation: "Ruta más corta = la de menor coste total. No importa si das 10 saltos de coste 1, es mejor que 1 salto de coste 100." },
  { question: "En un grafo dirigido,deg−(v)ydeg+(v)indican respectivamente…", options: [{ text: "La centralidad de cercanía y de intermediación de v", isCorrect: false }, { text: "El número de aristas que llegan a v y el número de aristas que salen de v", isCorrect: true }, { text: "El peso total que atraviesa v en ambos sentidos", isCorrect: false }, { text: "La cantidad de ciclos elementales que contienen a v", isCorrect: false }] , explanation: "In-degree (llegan) y out-degree (salen). Cuántos me apuntan vs a cuántos apunto." },
  { question: "En integración de fuentes, ¿qué significa “aterrizar en crudo y luego estandarizar”?", options: [{ text: "Guardar crudo y luego estandarizar", isCorrect: true }, { text: "Convertir todo a una gran tabla única desde el principio", isCorrect: false }, { text: "Reprocesar en origen hasta igualar todos los esquemas", isCorrect: false }, { text: "Cargar todo a memoria y limpiar en el dashboard", isCorrect: false }] , explanation: "Aterrizar en crudo = copia de seguridad exacta del origen. Si estandarizas antes de guardar y te equivocas, pierdes el dato original." },
  { question: "Para normalizar vocabularios distintos (p. ej., “Electro” vs “Electrónica”), lo adecuado es…", options: [{ text: "Usar índices en todas las tablas", isCorrect: false }, { text: "Mantener una tabla de correspondencias versionada", isCorrect: true }, { text: "Recalcular precios a una sola moneda", isCorrect: false }, { text: "Eliminar categorías minoritarias", isCorrect: false }] , explanation: "Tabla puente/diccionario: 'Electro' -> 'Electrónica'. Versionada por si cambia. No hagas hardcode de ifs en el código." },
  { question: "Antes de cruzar fuentes, uncontrol de calidad inicialefectivo debe…", options: [{ text: "Medir solo filas totales y continuar", isCorrect: false }, { text: "Documentar luego cualquier valor inesperado", isCorrect: false }, { text: "Seguir aunque falten claves y arreglar en el informe", isCorrect: false }, { text: "Verificar conteos, tipos, nulos, rangos y referencialidad; si un umbral crítico falla, parar y avisar con contexto y responsables", isCorrect: true }] , explanation: "Calidad inicial = barrera de entrada. Si el archivo viene vacío o corrupto, rompe el pipeline y avisa. Mejor no cargar nada que cargar basura." },
  { question: "En una reglasi p entonces q, ¿qué debe comprobar exactamente el test automático?", options: [{ text: "Que p y q se cumplan muchas veces", isCorrect: false }, { text: "Los contraejemplos: casos con p y no q", isCorrect: true }, { text: "Que p o q ocurra al menos una vez", isCorrect: false }, { text: "Que la media de p y q sea similar en el tiempo", isCorrect: false }] , explanation: "Para probar 'Si P entonces Q', busca a los que rompen la regla: cumplen P pero NO cumplen Q. Esos son tus errores." },
  { question: "En este contexto, la disyunción usada por defecto esinclusiva. ¿Qué significa eso?", options: [{ text: "Que solo cuenta cuando ocurre exactamente uno de los dos", isCorrect: false }, { text: "Que nunca permite que se cumplan a la vez", isCorrect: false }, { text: "Que considera válidos A, Bo ambos; la coincidencia no se excluye", isCorrect: true }, { text: "Que suma probabilidades sin ninguna corrección", isCorrect: false }] , explanation: "Disyunción inclusiva = o uno, o el otro, O LOS DOS. Como pedir 'cerveza o vino', puedes pedir ambas." },
  { question: "¿Qué expresa de forma correcta unbicondicionalentre p y q en una regla de datos?", options: [{ text: "Que p basta para q pero q no dice nada de p", isCorrect: false }, { text: "Que p y q deben coincidir siempre; si aparece uno sin el otro, hay violación", isCorrect: true }, { text: "Que p y q no pueden cumplirse a la vez", isCorrect: false }, { text: "Que p implica q solo cuando p es frecuente", isCorrect: false }] , explanation: "Bicondicional (si y solo si) = son siameses. Si está P tiene que estar Q, y si está Q tiene que estar P." },
  { question: "¿Cuál es el rasgo esencial de una reglaoperativaen un pipeline?", options: [{ text: "Que tenga una descripción extensa con muchos matices", isCorrect: false }, { text: "Que pueda traducirse en una consulta que devuelvesolo las violaciones", isCorrect: true }, { text: "Que dependa de si es lunes o festivo", isCorrect: false }, { text: "Que se ejecute sin registrar fecha ni N", isCorrect: false }] , explanation: "Regla operativa = código ejecutable. Si la regla es tan vaga que no puedes hacer un 'SELECT * FROM errores', no sirve en un pipeline." },
  { question: "Al diseñar una biblioteca de reglas, ¿qué práctica refleja mejor el objetivo del capítulo?", options: [{ text: "Comprobar que las filas “buenas” existen y contarlas", isCorrect: false }, { text: "Escribir la regla en llano, traducirla a conectores y auditar solodónde salta", isCorrect: true }, { text: "Mezclar varias ideas en una sola regla para ahorrar consultas", isCorrect: false }, { text: "Dejar excepciones sin etiquetar para evitar ruido", isCorrect: false }] , explanation: "Biblioteca de reglas: lenguaje humano -> SQL -> tabla de errores. Solo nos interesan las filas que NO cumplen." },
  { question: "Parapriorizaren un proyecto de datos, lo más efectivo es…", options: [{ text: "Ordenar por impacto y viabilidad usando MoSCoW y resultados observables", isCorrect: true }, { text: "Planificar tareas por orden de llegada sin evaluar retorno esperado", isCorrect: false }, { text: "Seguir un Gantt fijo sin revisiones de alcance ni foco", isCorrect: false }, { text: "Atender primero a quien presiona más dentro del equipo", isCorrect: false }] , explanation: "Priorizar = alto impacto + alta viabilidad primero. MoSCoW (Must, Should, Could, Won't) para acotar qué es indispensable." },
  { question: "Undiccionario de datosútil debería incluir…", options: [{ text: "Nombre y tipo con un comentario breve sin más detalle", isCorrect: false }, { text: "Nombre canónico, tipo, unidad, nulabilidad, fuente, definición y regla de calidad", isCorrect: true }, { text: "Solo un enlace a un dashboard con métricas relacionadas", isCorrect: false }, { text: "Un listado libre de notas sin formato ni responsable asignado", isCorrect: false }] , explanation: "Diccionario completo = cómo se llama, qué tipo, de dónde viene, qué significa y cómo se valida. Si falta algo, habrá dudas." },
  { question: "Paraversionar datos y modelosjunto al código conviene…", options: [{ text: "Subir binarios pesados a Git y anotar cambios manualmente", isCorrect: false }, { text: "Comprimir datasets en ZIP y adjuntar a cada pull request", isCorrect: false }, { text: "Usar DVC conarchivos.dvc, dvc.yaml y remoto configurado", isCorrect: true }, { text: "Guardar copias locales y compartir por correo cuando cambien", isCorrect: false }] , explanation: "Git es malo para archivos grandes (CSVs, modelos). DVC guarda el archivo pesado en S3 y solo trackea un puntero en Git." },
  { question: "En datos reales, “probabilidad” suele estimarse como…", options: [{ text: "La media histórica de todo el data lake, sin ventanas ni recortes", isCorrect: false }, { text: "Frecuencia en muestra reciente", isCorrect: true }, { text: "Una intuición del analista basada en experiencia", isCorrect: false }, { text: "El valor máximo observado en el histórico", isCorrect: false }] , explanation: "Probabilidad en el mundo real = contar cuántas veces pasó últimamente entre el total. Frecuencia observada." },
  { question: "La regla delcomplementose interpreta como…", options: [{ text: "Recalcular desde cero con una campaña nueva de medición", isCorrect: false }, { text: "Lo que falta para llegar a uno", isCorrect: true }, { text: "Sustituir por la tasa del mayor segmento", isCorrect: false }, { text: "Promediar con la tasa del periodo anterior", isCorrect: false }] , explanation: "Complemento = 1 - P(A). Si hay 30% de lluvia, hay 70% de no lluvia. La suma siempre es 1 (el todo)." },
  { question: "Para “AoB” sin doble contaje, debes…", options: [{ text: "Sumar A y B sin más ajustes", isCorrect: false }, { text: "Sumar las tasas individuales y restar la coincidencia para evitar contar dos veces", isCorrect: true }, { text: "Tomar solo el mayor de los dos valores", isCorrect: false }, { text: "Multiplicar ambas tasas en cualquier situación", isCorrect: false }] , explanation: "Prob(A o B) = Prob(A) + Prob(B) - Prob(A y B). Igual que la inclusión-exclusión de conjuntos." },
  { question: "Dos eventos sonindependientescuando…", options: [{ text: "Aparecen con la misma frecuencia en todos los meses", isCorrect: false }, { text: "Uno no informa del otro", isCorrect: true }, { text: "Nunca suceden a la vez", isCorrect: false }, { text: "Ocurren en días distintos del calendario", isCorrect: false }] , explanation: "Independientes = saber que pasó A no cambia la probabilidad de B. Tirar una moneda no afecta a la siguiente tirada." },
  { question: "Laprobabilidad condicionalse usa para…", options: [{ text: "Ampliar el universo a toda la base y mezclar segmentos sin control", isCorrect: false }, { text: "Medir la probabilidad de un evento dentro del subconjunto que cumple una condición, comparando con otros subconjuntos cuando haga falta", isCorrect: true }, { text: "Quitar de la muestra todo lo que no te gusta", isCorrect: false }, { text: "Evitar comparar segmentos entre sí", isCorrect: false }] , explanation: "Condicional: P(A|B) = 'prob de A SABIENDO QUE B ya pasó'. Acotas tu universo solo a los casos B." },
  { question: "En clave intuitiva,Bayessirve para…", options: [{ text: "Ignorar falsos positivos si la señal es fuerte", isCorrect: false }, { text: "Combinar señal y prevalencia para ajustar tu creencia", isCorrect: true }, { text: "Reemplazar la tasa base por la última alarma", isCorrect: false }, { text: "Usar siempre el mismo umbral pase lo que pase", isCorrect: false }] , explanation: "Bayes = tienes una sospecha inicial (prevalencia), llega nueva evidencia (señal), actualizas tu sospecha. No ignores la base." },
  { question: "Elmuestreo estratificadoes útil para…", options: [{ text: "Tomar los primeros registros que llegan por comodidad", isCorrect: false }, { text: "Representar subgrupos y ponderar su peso al combinarlos", isCorrect: true }, { text: "Evitar cualquier aleatoriedad en la selección", isCorrect: false }, { text: "Duplicar la tasa de los segmentos más grandes", isCorrect: false }] , explanation: "Estratificado = sacar una muestra que respete la proporción original (ej: 50% hombres, 50% mujeres). Evita muestras sesgadas." },
  { question: "Al publicar unatasa estimadaconviene añadir…", options: [{ text: "Solo el porcentaje con dos decimales y un emoji de estado", isCorrect: false }, { text: "N usada y, si puede ser, un margen aproximado de error o precisión", isCorrect: true }, { text: "Una captura de pantalla vistosa del dashboard", isCorrect: false }, { text: "El juicio del analista sin datos adicionales", isCorrect: false }] , explanation: "Tasa sola es engañosa. '100% de éxito' (de 1 intento). Pon la N (tamaño muestra) y el margen de error para dar contexto real." },
  { question: "Laclave primaria (PK)en una tabla debe ser…", options: [{ text: "Un texto legible por humanos que facilita informes", isCorrect: false }, { text: "Única, no nula y estable", isCorrect: true }, { text: "Corta y con prefijo del dominio", isCorrect: false }, { text: "La columna más consultada del sistema", isCorrect: false }] , explanation: "PK = tu DNI. No se repite, no puede faltar, y no debería cambiar con el tiempo." },
  { question: "Unaclave foránea (FK)es…", options: [{ text: "Un índice que acelera búsquedas entre tablas", isCorrect: false }, { text: "Apunta a una PK válida", isCorrect: true }, { text: "Un valor calculado para desnormalizar", isCorrect: false }, { text: "El alias visible del campo padre", isCorrect: false }] , explanation: "FK = enlace a otra tabla. Debe apuntar a un DNI (PK) que realmente exista en la tabla destino. Integridad referencial." },
  { question: "Unadependencia funcional$X \\to Y$ se interpreta como…", options: [{ text: "Si cambia Y, X también cambia", isCorrect: false }, { text: "Si X coincide, Y coincide", isCorrect: true }, { text: "X y Y son siempre claves", isCorrect: false }, { text: "Y determina transitivamente a X", isCorrect: false }] , explanation: "Dependencia funcional: DNI -> Nombre. Si dos filas tienen el mismo DNI, DEBEN tener el mismo Nombre. X determina Y." },
  { question: "Una relaciónN–Mse modela, sin duplicados, mediante…", options: [{ text: "Dos FKs en cada una de las tablas originales", isCorrect: false }, { text: "Tabla puente con PK compuesta", isCorrect: true }, { text: "Una PK natural distinta en cada lado", isCorrect: false }, { text: "Una vista materializada con UNION", isCorrect: false }] , explanation: "N a M = muchos a muchos (Alumnos y Asignaturas). Necesitas una tabla intermedia que una Alumno_ID con Asignatura_ID." },
  { question: "Con políticaRESTRICT / NO ACTIONen una FK, al borrar el padre…", options: [{ text: "Se borran automáticamente todos los hijos", isCorrect: false }, { text: "Bloquea el borrado con hijos", isCorrect: true }, { text: "Pone la FK de los hijos a NULL", isCorrect: false }, { text: "Se reasignan hijos al valor por defecto", isCorrect: false }] , explanation: "RESTRICT = si el cliente tiene pedidos, la base de datos no te deja borrar al cliente. Evita dejar pedidos huérfanos." },
  { question: "ElPrincipio Fundamental del Conteo (PFC)dice que el total se obtiene…", options: [{ text: "Suma de opciones entre pasos", isCorrect: false }, { text: "Producto de opciones en pasos independientes", isCorrect: true }, { text: "Máximo entre los pasos", isCorrect: false }, { text: "Promedio ponderado de opciones por paso con ajustes", isCorrect: false }] , explanation: "Principio conteo: Si hay 3 primeros platos y 4 segundos, tienes 3 x 4 = 12 menús posibles. Multiplicas opciones." },
  { question: "Para dos conjuntos, launiónse cuenta correctamente…", options: [{ text: "Sumando ambos tamaños sin más", isCorrect: false }, { text: "Sumar ambos y restar lo común", isCorrect: true }, { text: "Usar solo el tamaño de la intersección", isCorrect: false }, { text: "Restar el menor del mayor en cualquier caso", isCorrect: false }] , explanation: "Unión: igual que en probabilidad, sumas los tamaños y restas la intersección para no contarla doble." },
  { question: "Laspermutaciones sin repeticiónde n elementos tomados k consisten en…", options: [{ text: "Elegir un subconjunto y luego ignorar el orden", isCorrect: false }, { text: "Probar cualquier orden incluso repitiendo elementos", isCorrect: false }, { text: "Encadenar elecciones donde cada nueva posición reduce en uno las opciones disponibles, sin reutilizar elementos y respetando el orden de colocación", isCorrect: true }, { text: "Usar un árbol donde todas las ramas tienen el mismo número de hijos", isCorrect: false }] , explanation: "Permutaciones: importa el orden, sin repetición. N * (N-1) * (N-2)... Para carreras, podios, contraseñas únicas." },
  { question: "Lascombinaciones sin repetición(orden no importa) se obtienen…", options: [{ text: "Tomando todas las ordenaciones y quedándote con la más corta", isCorrect: false }, { text: "Tomando todas las ordenaciones posibles y eliminando el efecto del orden interno del subconjunto", isCorrect: true }, { text: "Sumando opciones de cada paso sin ajustar nada", isCorrect: false }, { text: "Eligiendo primero el orden y luego el subconjunto", isCorrect: false }] , explanation: "Combinaciones = eliges subconjunto y NO importa el orden. Divides las permutaciones entre el factorial del grupo para quitar el orden." },
  { question: "Lascombinaciones con repeticiónse interpretan como…", options: [{ text: "Repartir sin reposición y con orden estricto", isCorrect: false }, { text: "Elegir con reposición y sin importar el orden", isCorrect: true }, { text: "Permutar elementos distintos en posiciones distintas", isCorrect: false }, { text: "Sumar tamaños por tipo y dividir por el número de tipos", isCorrect: false }] , explanation: "Combinaciones con repetición = vas a la heladería, puedes pedir dos bolas de fresa, y da igual el orden en que te las pongan en la tarrina." },
  { question: "Elcoeficiente multinomialse usa para…", options: [{ text: "Forzar tamaños iguales en todos los grupos", isCorrect: false }, { text: "Contar arreglos cuando hay grupos de elementos indistinguibles, corrigiendo las permutaciones internas de cada grupo", isCorrect: true }, { text: "Elegir un único subconjunto sin repeticiones", isCorrect: false }, { text: "Ordenar columnas por popularidad", isCorrect: false }] , explanation: "Multinomial = ordenar letras de 'MISSISSIPPI'. Como hay letras repetidas idénticas, divides por el factorial de las repeticiones para no contar de más." },
  { question: "Laspermutaciones circularesde elementos distintos se cuentan…", options: [{ text: "Igual que en fila, porque girar no cambia nada", isCorrect: false }, { text: "Repitiendo el primer elemento al final y contando lineal", isCorrect: false }, { text: "Fijas uno y ordenas el resto", isCorrect: true }, { text: "Marcas la mitad y permutas la otra mitad", isCorrect: false }] , explanation: "Circular = en una mesa redonda no hay principio ni fin. Sientas a uno fijo y permutas al resto: (N-1)!" },
  { question: "Ensecuencias con repetición y con orden, el número de cadenas posibles se calcula…", options: [{ text: "Eligiendo un subconjunto sin atender al orden", isCorrect: false }, { text: "Haciendo que cada posición elija de forma independiente entre todas las opciones disponibles", isCorrect: true }, { text: "Restando el número de posiciones al tamaño del alfabeto", isCorrect: false }, { text: "Evitando repetir símbolos contiguos por norma", isCorrect: false }] , explanation: "Secuencias con repetición (orden sí): candado de 3 ruedas con 10 números. 10 x 10 x 10. Cada paso tiene todas las opciones libres." },
  { question: "En la comparación entre Lambda y Kappa, ¿qué diferencia estructural describe mejor la organización del procesamiento?", options: [{ text: "Lambda usa un único pipeline de streaming y Kappa separa batch y speed layer en paralelo", isCorrect: false }, { text: "Lambda mantiene una capa batch y otra speed, mientras Kappa propone un único flujo de streaming", isCorrect: true }, { text: "Ambas arquitecturas exigen siempre dos capas de batch independientes y una speed layer secundaria", isCorrect: false }, { text: "Ambas arquitecturas prohíben el uso de batch histórico, priorizando solo el streaming en producción", isCorrect: false }] , explanation: "Lambda = doble vía (batch + streaming) que se juntan al final. Kappa = vía única (todo es streaming, incluso el histórico)." },
  { question: "En una organización con fuerte legado batch y un data lake consolidado, ¿por qué suele considerarse Lambda una evolución natural?", options: [{ text: "Porque obliga a sustituir todo el procesamiento batch anterior por un único pipeline de streaming global", isCorrect: false }, { text: "Porque reduce el histórico a solo datos del día actual, simplificando el mantenimiento de la plataforma", isCorrect: false }, { text: "Porque permite añadir una speed layer sobre lo ya existente, sin tirar procesos batch consolidados", isCorrect: true }, { text: "Porque impone reescribir la lógica batch en SQL puro, independientemente de las herramientas anteriores", isCorrect: false }] , explanation: "Lambda es pragmática: si ya tienes un batch gigante funcionando, le pones una capita rápida al lado para lo urgente y no rompes lo viejo." },
  { question: "Respecto a la ingesta batch, ¿qué característica la diferencia claramente de la ingesta streaming en términos operativos?", options: [{ text: "Se ejecuta continuamente, evento a evento, manteniendo siempre latencias de milisegundos entre origen y destino", isCorrect: false }, { text: "Trabaja con eventos individuales sin compresión, que se consumen en tiempo real desde colas de mensajes", isCorrect: false }, { text: "Su diseño obliga a procesar únicamente datos del día en curso, sin acceder a histórico almacenado", isCorrect: false }, { text: "Se basa en cargas periódicas de grandes ficheros, con ventanas de tiempo definidas y cierto retraso asumido", isCorrect: true }] , explanation: "Ingesta Batch = camión de mudanzas. Viene cada X horas, carga un bloque enorme de datos y lo vuelca. Lento pero eficiente." },
  { question: "Cuando se habla de ingesta streaming como “puerta rápida” de entrada al lago de datos, ¿qué implicación técnica es clave tener en cuenta?", options: [{ text: "La necesidad de gestionar picos de tráfico, backpressure, orden de eventos y políticas de retención", isCorrect: true }, { text: "La obligación de desactivar cualquier mecanismo de compresión para priorizar solo el tamaño de los ficheros", isCorrect: false }, { text: "La imposibilidad de persistir los eventos en bruto, ya que el streaming no admite almacenamiento histórico", isCorrect: false }, { text: "La necesidad de que todos los productores escriban exclusivamente en ficheros planos locales sin usar colas", isCorrect: false }] , explanation: "Streaming = grifo abierto. Tienes que gestionar si el agua sale muy fuerte (backpressure), si llega desordenada o si no cabe en el sumidero." },
  { question: "En una arquitectura Kappa, ¿cómo se aborda típicamente la necesidad de reprocesar el histórico cuando cambia la lógica de negocio?", options: [{ text: "Se lanza un job batch independiente que ejecuta una lógica distinta a la del pipeline de streaming", isCorrect: false }, { text: "Se rebobina el log de eventos y se reprocesa el flujo completo usando el mismo código de streaming", isCorrect: true }, { text: "Se descartan todos los eventos anteriores a la nueva versión y solo se procesan eventos futuros", isCorrect: false }, { text: "Se migra temporalmente el sistema a una arquitectura Lambda, añadiendo una batch layer para esa tarea", isCorrect: false }] , explanation: "Kappa no tiene batch. Si cambias el código, rebobinas Kafka (o similar) al principio de los tiempos y vuelves a procesar todos los eventos pasados." },
  { question: "En la arquitectura Lambda, ¿qué papel juega la serving layer respecto a la batch layer y la speed layer?", options: [{ text: "Generar directamente los eventos de origen que alimentan tanto a la capa batch como a la capa rápida", isCorrect: false }, { text: "Servir únicamente datos en tiempo real, ignorando completamente cualquier resultado proveniente de la capa batch", isCorrect: false }, { text: "Combinar vistas históricas estables con resultados recientes en vivo para responder consultas al negocio", isCorrect: true }, { text: "Sustituir a la ingesta batch, encargándose de volcar directamente los datos transaccionales al data lake", isCorrect: false }] , explanation: "Serving layer (Lambda) = el camarero que junta el plato cocinado a fuego lento (batch) con el aderezo rápido de última hora (speed) para el cliente." },
  { question: "¿Cómo se relacionan Kafka, Spark y Flink con las decisiones sobre Lambda, Kappa y los tipos de ingesta en una plataforma Big Data?", options: [{ text: "Spark siempre debe usarse solo para speed layer, mientras Kafka y Flink se reservan exclusivamente al batch histórico", isCorrect: false }, { text: "Kafka se limita a servir como data warehouse central, mientras Spark y Flink solo gestionan la ingesta batch", isCorrect: false }, { text: "Spark solo es válido en entornos Kappa, y Flink queda restringido a arquitecturas Lambda con alta latencia", isCorrect: false }, { text: "Kafka encaja en la ingesta streaming, Spark suele dominar el batch y Flink gana peso en pipelines de streaming avanzados", isCorrect: true }] , explanation: "Kafka = buzón de eventos. Spark = rey del batch/micro-batch. Flink = rey del streaming puro y complejo." },
  { question: "En términos de coste y calidad, ¿qué trade-off destaca al comparar Lambda con Kappa en la práctica?", options: [{ text: "Lambda ofrece gran flexibilidad sobre el histórico pero aumenta la duplicidad de lógica y la complejidad operativa", isCorrect: true }, { text: "Lambda reduce al mínimo el histórico disponible, logrando menos complejidad a costa de perder capacidad de análisis", isCorrect: false }, { text: "Kappa exige mantener dos implementaciones de cada transformación pero simplifica radicalmente la ingesta batch", isCorrect: false }, { text: "Kappa garantiza que nunca se necesiten reprocesos, eliminando la necesidad derecursosadicionales para el histórico", isCorrect: false }] , explanation: "Problema Lambda: tienes que programar y mantener la misma lógica de negocio dos veces, una en batch y otra en streaming. Doble trabajo." },
  { question: "En muchas plataformas maduras, ¿qué patrón describe mejor la relación entre ingesta streaming y mundo batch dentro del data lake?", options: [{ text: "La ingesta streaming se utiliza solo para monitorización y no tiene impacto sobre los datos históricos almacenados", isCorrect: false }, { text: "Los eventos entran en streaming, se persisten en bruto y luego se reescriben en formatos aptos para jobs batch", isCorrect: true }, { text: "La ingesta batch genera continuamente eventos sintéticos para alimentar una capa de streaming puramente decorativa", isCorrect: false }, { text: "Los dos tipos de ingesta permanecen totalmente aislados, sin compartir nunca datos ni estructuras comunes en el lago", isCorrect: false }] , explanation: "Patrón mixto: ingesta rápida vía Kafka -> se guarda en crudo (bronze) -> un job batch lo compacta en Parquet para que sea eficiente de consultar." },
  { question: "Al decidir entre acercarse más a Lambda o a Kappa, ¿qué combinación de factores humanos y técnicos enfatiza el texto como relevante?", options: [{ text: "Solo la moda tecnológica del momento y el número de logotipos conocidos en el diagrama de arquitectura", isCorrect: false }, { text: "El tamaño de losarchivosCSV disponibles y la cantidad de informes que se desean imprimir en papel", isCorrect: false }, { text: "La cultura del equipo respecto a batch y eventos, junto con las necesidades reales de latencia y complejidad", isCorrect: true }, { text: "La obligación de cumplir siempre con Lambda primero y migrar obligatoriamente a Kappa en una segunda fase", isCorrect: false }] , explanation: "Tecnología = personas. Si tu equipo solo sabe SQL/batch, meter Kappa (streaming puro) los hundirá. La decisión técnica también es humana." },
  { question: "Al definirrecursospara jobs de datos en Kubernetes, ¿qué ventaja práctica aportan los contenedores frente a instalaciones “a mano” en servidores?", options: [{ text: "Permiten ejecutar todas las aplicaciones compartiendo la misma JVM y librerías del nodo físico", isCorrect: false }, { text: "Permiten empaquetar versión, dependencias y límites de CPU/RAM de forma consistente entre entornos", isCorrect: true }, { text: "Obligan a que cada job use siempre todos losrecursosdisponibles del clúster", isCorrect: false }, { text: "Garantizan que no es necesario monitorizar el consumo de memoria ni el uso de CPU", isCorrect: false }] , explanation: "Contenedores = caja sellada. Lleva su código, sus librerías y sus límites de hardware. Funciona igual en tu portátil que en el servidor de prod." },
  { question: "¿Qué problema típico aparece cuando se adopta el patrón de “contenedor monstruo” en una plataforma Big Data?", options: [{ text: "Se obliga a que cada contenedor ejecute únicamente una sola tarea trivial en background", isCorrect: false }, { text: "Se asegura que el clúster mantenga siempre un consumo mínimo derecursosy baja facturación", isCorrect: false }, { text: "Se concentran demasiadas funciones y memoria en pocas instancias, saturando el clúster con pocas réplicas", isCorrect: true }, { text: "Se impide totalmente escalar horizontalmente, ya que los contenedores no pueden replicarse por diseño", isCorrect: false }] , explanation: "Contenedor monstruo = meter todo en una imagen de 10GB que pide 64GB RAM. Kubernets no sabrá dónde meterlo y no escalará bien." },
  { question: "En Kafka, ¿qué relación existe entre el número de particiones de un topic y el paralelismo máximo efectivo de consumo?", options: [{ text: "El número de particiones fija el máximo de consumidores activos por consumer group que realmente reciben datos", isCorrect: true }, { text: "El número de particiones solo afecta al tamaño de los mensajes, no al paralelismo real", isCorrect: false }, { text: "El número de particiones obliga a tener siempre el mismo número de brokers en el clúster", isCorrect: false }, { text: "El número de particiones determina exclusivamente la retención temporal, sin impacto en la concurrencia", isCorrect: false }] , explanation: "Kafka: 1 partición = 1 consumidor concurrente máximo. Si tienes 10 particiones y 20 consumidores, 10 estarán parados mirando. Particiones dictan paralelismo." },
  { question: "Al dimensionar particiones en Kafka, ¿por qué es relevante la elección de la clave de particionado para la distribución de carga?", options: [{ text: "Porque la clave determina qué mensajes se borran antes cuando se llena el disco de los brokers", isCorrect: false }, { text: "Porque la clave decide qué consumidor del grupo tendrá privilegios administrativos sobre el topic compartido", isCorrect: false }, { text: "Porque la clave obliga a que cada partición tenga exactamente el mismo volumen de datos en bytes", isCorrect: false }, { text: "Porque la clave controla qué eventos van a cada partición y puede crear hotspots si concentra tráfico", isCorrect: true }] , explanation: "Kafka key: si usas 'país' como clave, España y Andorra van a particiones distintas. Pero España colapsará su partición y Andorra estará vacía (hotspot)." },
  { question: "En Spark, ¿qué síntoma indica con más probabilidad que existe un problema de data skew en un job distribuido?", options: [{ text: "Todas las tareas del stage terminan exactamente en el mismo segundo en todos los ejecutores", isCorrect: false }, { text: "Una tarea tarda mucho más que el resto mientras la mayoría de ejecutores quedan ociosos", isCorrect: true }, { text: "El job falla inmediatamente al comenzar, antes de que se planifiquen tareas en los ejecutores", isCorrect: false }, { text: "Todas las tareas tienen duraciones muy cortas, con miles de stages encadenados en pocos segundos", isCorrect: false }] , explanation: "Data skew = datos mal repartidos. Un nodo tiene 1 millón de registros y los demás 10. Todos acaban rápido y se quedan esperando al lento." },
  { question: "¿Cuál es una consecuencia directa de usar muy pocas particiones de DataFrame en Spark respecto al número total de cores disponibles?", options: [{ text: "Se obliga a Spark a deshabilitar el almacenamiento en caché para evitar inconsistencias entre ejecutores", isCorrect: false }, { text: "Se incrementa el coste de coordinación del scheduler por manejar demasiadas tareas breves simultáneas", isCorrect: false }, { text: "Se infrautilizan los cores, ya que pocas tareas largas ocupan solo una fracción del paralelismo posible", isCorrect: true }, { text: "Se eliminan automáticamente los fallos por pérdida de ejecutores, al simplificar la planificación global", isCorrect: false }] , explanation: "Pocas particiones = pocos 'trozos' de trabajo. Si tienes 100 cores y 5 particiones, solo trabajan 5 cores. Has tirado el dinero del clúster." },
  { question: "En Flink, ¿cómo impacta la combinación de un `keyBy` mal elegido y un parallelism bajo sobre un flujo de eventos de alto volumen?", options: [{ text: "Provoca que una o pocas subtareas acumulen la mayoría del tráfico, saturando CPU y memoria mientras otras quedan infrautilizadas", isCorrect: true }, { text: "Garantiza que todos los operadores se repartan equitativamente el estado, independientemente de la distribución de claves", isCorrect: false }, { text: "Evita la necesidad de checkpoints, ya que el estado se replica automáticamente en todas las subtareas", isCorrect: false }, { text: "Reduce el consumo de red a cero, dado que los eventos nunca se redistribuyen entre instancias de operadores", isCorrect: false }] , explanation: "Flink keyBy con clave sesgada: mandas casi todos los eventos a la misma subtarea. Ese operador explota por CPU/RAM mientras los demás bostezan." },
  { question: "¿Qué factor se debe considerar al diseñar el esquema de particionado en disco de un data lake basado en Parquet?", options: [{ text: "Elegir siempre como partición la columna con más valores distintos, aunque nadie consulte por ella", isCorrect: false }, { text: "Elegir particiones alineadas con las consultas frecuentes, equilibrando tamaño de directorios y número de ficheros", isCorrect: true }, { text: "Evitar cualquier tipo de partición y volcar todos los datos en un único directorio raíz", isCorrect: false }, { text: "Particionar exclusivamente por identificador único de registro para garantizar que no haya solapamientos temporales", isCorrect: false }] , explanation: "Partición en disco = carpetas. Si particionas por fecha (útil, tamaño sano), bien. Si particionas por milisegundo (millones de carpetas vacías), mal." },
  { question: "En relación con los formatos columnares, ¿qué ventaja concreta aporta Parquet al ejecutar consultas analíticas sobre grandes tablas?", options: [{ text: "Permite modificar registros individuales en disco sin reescribir bloques completos ni afectar al resto de columnas", isCorrect: false }, { text: "Permite leer siempre todas las columnas de la tabla en un único acceso secuencial garantizado", isCorrect: false }, { text: "Permite leer solo columnas necesarias y saltar bloques completos mediante predicate pushdown sobre metadatos", isCorrect: true }, { text: "Permite desactivar totalmente la compresión para priorizar tamaño constante de fichero frente a rendimiento de lectura", isCorrect: false }] , explanation: "Parquet: columnar y con min/max por bloque. Consulta rápida porque ignora columnas que no pides y se salta bloques que sabe que no tienen tu dato." },
  { question: "¿Por qué los procesos de compaction sobre ficheros Parquet son importantes en la planificación derecursosde un data lake?", options: [{ text: "Porque generan automáticamente índices secundarios en cada fichero, eliminando la necesidad de particionado en disco", isCorrect: false }, { text: "Porque convierten tablas Parquet en formatos fila, facilitando su lectura manual por parte de usuarios finales", isCorrect: false }, { text: "Porque reducen el número de small files, mejorando la eficiencia de lectura y el uso derecursosdel clúster", isCorrect: true }, { text: "Porque permiten almacenar los datos exclusivamente en memoria, prescindiendo por completo del sistema dearchivos", isCorrect: false }] , explanation: "Compaction: juntar miles de CSV/Parquet enanos en unos pocos grandes. HDFS y Spark sufren abriendo miles de archivitos. Un archivo grande rinde mucho más." },
  { question: "En un job de Spark donde varios pasos comparten el mismo join costoso, ¿cuándo tiene más sentido aplicar cache() sobre el resultado intermedio?", options: [{ text: "Cuando el DataFrame resultante es enorme, se usa una sola vez y ya no se vuelve a leer", isCorrect: false }, { text: "Cuando el resultado del join es caro de obtener y se reutiliza en varias acciones posteriores", isCorrect: true }, { text: "Cuando el resultado es muy pequeño y su cálculo es trivial frente al resto del pipeline", isCorrect: false }, { text: "Cuando se quiere evitar por completo que Spark pueda recalcular cualquier transformación del DAG", isCorrect: false }] , explanation: "Cache = guardar en RAM. Solo hazlo si la tabla te costó mucho generarla Y la vas a usar varias veces. Si la usas una vez, es gasto inútil de memoria." },
  { question: "En un join entre una tabla de eventos masiva y una tabla de dimensiones pequeña, ¿qué efecto persigue explícitamente el uso de broadcast en Spark?", options: [{ text: "Forzar que ambas tablas se mezclen mediante un gran shuffle centralizado en el driver", isCorrect: false }, { text: "Minimizar el número de particiones de salida reduciendo el paralelismo del job completo", isCorrect: false }, { text: "Enviar la tabla pequeña a cada executor para realizar el join localmente y reducir tráfico de red", isCorrect: true }, { text: "Garantizar que la tabla grande se mantenga siempre en memoria en todos los nodos del clúster", isCorrect: false }] , explanation: "Broadcast Join = copiar la tabla pequeña entera a todos los nodos. Evita que la tabla grande tenga que moverse por la red (shuffle) para hacer el cruce." },
  { question: "En términos de coste de serialización, ¿cuál de las siguientes prácticas suele ser más favorable para el rendimiento de un pipeline distribuido?", options: [{ text: "Utilizar estructuras de datos sencillas y tipos nativos del motor en lugar de objetos muy anidados", isCorrect: true }, { text: "Empaquetar toda la información posible en una única cadena JSON almacenada en una sola columna", isCorrect: false }, { text: "Utilizar clases con lógica compleja y muchos campos opcionales para encapsular cada registro", isCorrect: false }, { text: "Elegir siempre el serializador más compacto aunque multiplique varias veces el tiempo de CPU", isCorrect: false }] , explanation: "Serialización = convertir objetos en bytes para red/disco. Objetos Java complejos = serialización lenta y gorda. Tipos nativos (int, string) = bala." },
  { question: "En un stream que lee de Kafka y escribe en una base de datos, ¿qué estrategia ayuda a tolerar fallos cuando se trabaja con semántica at-least-once?", options: [{ text: "Confirmar el offset de Kafka inmediatamente al leer el mensaje, antes de iniciar el procesamiento", isCorrect: false }, { text: "Reiniciar siempre la lectura desde el principio del topic para evitar perder cualquier mensaje en fallos", isCorrect: false }, { text: "Diseñar escrituras idempotentes o con deduplicación para que reprocesar mensajes no genere resultados incorrectos", isCorrect: true }, { text: "Guardar el estado solo en memoria local del proceso, sin checkpoints ni registros de progreso", isCorrect: false }] , explanation: "At-least-once = puede que envíe el mensaje 2 veces. Solución: la escritura debe ser idempotente. Insertar 2 veces debe dejar el mismo resultado que 1." },
  { question: "Al configurar checkpoints en un job de Flink con estado grande, ¿qué compromiso se está gestionando principalmente al elegir su frecuencia?", options: [{ text: "El equilibrio entre el número de particiones Kafka y la retención máxima de los topics del clúster", isCorrect: false }, { text: "El equilibrio entre cuánto trabajo se pierde tras un fallo y el coste de hacer snapshots frecuentes", isCorrect: true }, { text: "La decisión de si el stream tendrá semántica at-most-once o strictly-once en todos los casos", isCorrect: false }, { text: "El tamaño máximo que pueden alcanzar los objetos Java antes de ser serializados en el heap del JVM", isCorrect: false }] , explanation: "Checkpoints = guardar partida. Muchos = pierdes poco si mueres, pero el juego va lento. Pocos = el juego va fluido, pero si mueres repites un montón." },
  { question: "¿Cuál de las siguientes métricas encaja mejor como SLI para evaluar la salud de un pipeline batch de cierre diario?", options: [{ text: "El número total de pods desplegados en el clúster durante el último año natural", isCorrect: false }, { text: "La cantidad de columnas definidas en el esquema lógico del data warehouse histórico", isCorrect: false }, { text: "El tiempo que tarda el job en completar la ventana de datos comprometida, medido de forma consistente", isCorrect: true }, { text: "El recuento acumulado de mensajes de log con nivel INFO generados por todos los jobs", isCorrect: false }] , explanation: "SLI de Batch = '¿termina en su ventana?'. El usuario quiere sus datos a las 8:00 AM. Cuántos pods uses da igual, importa cumplir el deadline." },
  { question: "Un equipo define como SLO que “la latencia p95 de un stream crítico sea menor de 2 segundos”. ¿Cómo debería influir esto en las decisiones de diseño y capacidad?", options: [{ text: "Obligando a que todos los jobs batch compartan el mismo clúster de streaming para reutilizarrecursos", isCorrect: false }, { text: "Sirviendo de referencia para dimensionar paralelismo, particiones y tamaño de clúster en función de la carga real", isCorrect: true }, { text: "Impidiendo hacer cambios en el esquema de datos mientras el valor de p95 sea inferior a 1 segundo", isCorrect: false }, { text: "Marcando que cualquier latencia inferior a ese umbral es desperdicio derecursosy debe incrementarse", isCorrect: false }] , explanation: "SLO = la meta técnica. Si la meta es <2s, el diseño de particiones, memoria y nodos se calcula en base a asegurar ese número, no al azar." },
  { question: "¿Qué elemento de observabilidad resulta más adecuado para detectar que un operador concreto está causando backpressure en un job de Flink?", options: [{ text: "Un log puntual en texto plano que se escribe solo al iniciar el job en el cluster manager", isCorrect: false }, { text: "Una traza distribuida que solo mide el tiempo de respuesta de la API de entrada del sistema", isCorrect: false }, { text: "Métricas de latencia, tamaño de colas internas y duración de backpressure asociadas a ese operador", isCorrect: true }, { text: "Un contador global del número de tablas Parquet generadas por todos los jobs durante el mes", isCorrect: false }] , explanation: "Backpressure = atasco de tráfico en Flink. Lo mides mirando si el buzón de entrada de un operador está lleno y bloqueando a los que le envían datos." },
  { question: "¿Por qué los logs estructurados con campos como job_id, partition u offset son especialmente útiles en sistemas distribuidos de datos?", options: [{ text: "Porque obligan a que todos los servicios usen el mismo lenguaje de programación para escribir mensajes", isCorrect: false }, { text: "Porque permiten correlacionar eventos y errores entre componentes distintos y localizar problemas concretos", isCorrect: true }, { text: "Porque reducen automáticamente el volumen total de logs generados por el sistema en producción", isCorrect: false }, { text: "Porque sustituyen la necesidad de cualquier métrica numérica, haciendo innecesarios los dashboards", isCorrect: false }] , explanation: "Log estructurado = JSON con ID de transacción. Cuando algo falla en 5 microservicios, el ID te permite trazar el camino exacto del error en Kibana." },
  { question: "Al hablar de “pipeline que funciona pero va justo”, ¿qué enfoque describe mejor una respuesta madura en términos de rendimiento y confiabilidad?", options: [{ text: "Reiniciar periódicamente todos los jobs para que empiecen de cero y evitar la acumulación de lag", isCorrect: false }, { text: "Centrarse únicamente en optimizar el código de negocio, ignorando particionamiento, serialización y checkpoints", isCorrect: false }, { text: "Definir SLIs y SLOs claros, revisar particiones, caches, checkpoints y observabilidad para atacar cuellos de botella", isCorrect: true }, { text: "Migrar todo el sistema a una tecnología distinta sin análisis previo, asumiendo que el problema es la herramienta", isCorrect: false }] , explanation: "Pipeline 'va justo' = diagnóstico médico. Mides con SLOs, miras cuellos de botella reales, ajustas config. Nada de reescribir todo a lo loco." },
  { question: "En el contexto de una plataforma Big Data, ¿qué describe mejor el concepto de TCO (Total Cost of Ownership)?", options: [{ text: "Solo la suma de las facturas de infraestructura de la nube del último mes contemplado en el proyecto", isCorrect: false }, { text: "El conjunto de costes de infraestructura, licencias, personas y operación necesarios para mantener viva la plataforma durante años", isCorrect: true }, { text: "Únicamente las horas de desarrollo inicial de los pipelines, sin considerar mantenimiento ni monitorización posterior", isCorrect: false }, { text: "Principalmente el precio de los servicios gestionados contratados, suponiendo que el resto de costes son despreciables", isCorrect: false }] , explanation: "TCO = lo que de verdad cuesta el coche. No solo el precio de compra, sino gasolina, seguro, taller, impuestos durante 5 años. La nube engaña si solo miras la factura." },
  { question: "¿Cuál de las siguientes decisiones tiende a reducir el TCO de una plataforma Big Data sin cambiar necesariamente las herramientas base?", options: [{ text: "Incrementar al máximo el tamaño de todos los clústeres para evitar cualquier posible saturación derecursosen producción", isCorrect: false }, { text: "Diseñar jobs eficientes que lean menos datos, usen Parquet y buen particionado para necesitar menos nodos de cómputo", isCorrect: true }, { text: "Mantener versiones diferentes de cada tecnología en cada entorno para probar más combinaciones posibles", isCorrect: false }, { text: "Duplicar todos los pipelines en dos motores distintos para tener alternativas técnicas en todo momento", isCorrect: false }] , explanation: "Mejor TCO = ingeniería eficiente. Un buen particionado y Parquet hace que un trabajo necesite 10 nodos en vez de 100. Ahorras nube optimizando código." },
  { question: "En términos de complejidad operativa, ¿qué escenario suele ser más delicado de mantener a medio plazo?", options: [{ text: "Una plataforma con muchos motores y bases de datos distintos añadidos sin plan claro, cada uno operado por pocas personas", isCorrect: true }, { text: "Un entorno con pocas herramientas bien documentadas y pipelines que siguen convenciones comunes y contratos claros", isCorrect: false }, { text: "Una plataforma donde se han estandarizado conectores, formatos y mecanismos de despliegue entre equipos de datos", isCorrect: false }, { text: "Un sistema en el que la monitorización está centralizada y existen paneles compartidos con métricas críticas de la plataforma", isCorrect: false }] , explanation: "Zoo tecnológico = muchas herramientas 'cool', pocos expertos. Cuando algo falla, nadie sabe arreglarlo. Complejidad operativa se dispara y el mantenimiento se hace inasumible." },
  { question: "En la decisión de añadir un nuevo motor de streaming a una plataforma ya operativa, ¿qué criterio alinea mejor coste y calidad?", options: [{ text: "Incorporar siempre la última tecnología publicada en conferencias, independientemente de los SLOs o de los casos de uso reales", isCorrect: false }, { text: "Mantener indefinidamente el stack actual, aunque sea incapaz de cumplir los objetivos de latencia exigidos por el negocio", isCorrect: false }, { text: "Introducir un nuevo motor solo si mejora claramente un SLO relevante o reduce el TCO frente a las opciones existentes", isCorrect: true }, { text: "Añadir motores de forma preventiva para no tener que justificar su incorporación más adelante ante el equipo directivo", isCorrect: false }] , explanation: "Añadir tecnología = coste de peaje. Solo se paga si ganas velocidad real (cumples un SLO que no podías) o te ahorras mucho dinero (TCO). No por moda." },
  { question: "Respecto al trade-off entre latencia y simplicidad, ¿qué enfoque suele ser razonable para un primer diseño de plataforma?", options: [{ text: "Apuntar siempre a latencias de milisegundos aunque el negocio solo necesite refrescos cada pocas horas", isCorrect: false }, { text: "Empezar con soluciones batch o microbatch más simples, elevando la complejidad de streaming solo si la latencia lo exige", isCorrect: true }, { text: "Evitar cualquier tipo de procesamiento batch y forzar que todo se haga como streaming nativo desde el principio", isCorrect: false }, { text: "Dividir todo pipeline en tres motores distintos para repartir la responsabilidad de la latencia entre múltiples componentes", isCorrect: false }] , explanation: "KISS: empieza batch. Si luego te piden datos al minuto, pasas a streaming. El streaming es complejo y caro de operar. No lo metas si nadie lo pide." },
  { question: "En el conflicto entre calidad de datos y coste de procesamiento, ¿qué decisión refleja mejor una apuesta fuerte por la calidad histórica?", options: [{ text: "Limitarse a aceptar cualquier dato entrante sin validación para reducir el tiempo de cómputo y simplificar los jobs", isCorrect: false }, { text: "Posponer indefinidamente cualquier corrección histórica y prohibir reprocesados para no consumirrecursosadicionales", isCorrect: false }, { text: "Diseñar procesos de validación y reprocesado batch que permitan corregir errores, asumiendo coste extra de cómputo", isCorrect: true }, { text: "Reducir el número de métricas disponibles para que solo se calculen las que sean más baratas de obtener", isCorrect: false }] , explanation: "Calidad > Coste. Si priorizas calidad, asumes que vas a reprocesar (gastar cómputo) para limpiar el histórico cuando detectes un bug en tu lógica anterior." },
  { question: "Respecto al equilibrio entre flexibilidad y estandarización tecnológica, ¿qué práctica suele ayudar a contener el “zoológico de herramientas”?", options: [{ text: "Permitir que cada equipo use cualquier tecnología sin restricciones siempre que la instale por su cuenta en producción", isCorrect: false }, { text: "Mantener una única tecnología obligatoria aunque no se adapte a casos de uso críticos y fuerce soluciones forzadas", isCorrect: false }, { text: "Definir un conjunto reducido de tecnologías soportadas y evaluar excepciones solo cuando aporten beneficios claros y medibles", isCorrect: true }, { text: "Cambiar de motor principal cada año para “aprovechar” las novedades del mercado sin acumular legado tecnológico", isCorrect: false }] , explanation: "Catálogo de herramientas estándar. Todo el mundo usa lo mismo. Excepciones solo con caso de negocio blindado. Evita el zoo tecnológico." },
  { question: "En el eje autoservicio vs. control centralizado, ¿qué riesgo suele aparecer cuando se impulsa el autoservicio sin invertir en gobernanza?", options: [{ text: "Que los equipos de negocio pierdan interés y dejen de crear nuevos datasets para sus propias necesidades analíticas", isCorrect: false }, { text: "Que la plataforma se vuelva totalmente inaccesible, requiriendo siempre la intervención del equipo central para cualquier cambio menor", isCorrect: false }, { text: "Que proliferen “mini data lakes” inconsistentes, métricas duplicadas y pipelines opacos sin estándares comunes", isCorrect: true }, { text: "Que ninguna métrica pueda ser calculada sin aprobación formal previa del comité de arquitectura corporativo", isCorrect: false }] , explanation: "Autoservicio total sin gobierno = feudalismo. Cada equipo crea su feudo de datos, las métricas no cruzan, nadie sabe qué es fuente de verdad." },
  { question: "Al comparar infraestructura propia con servicios gestionados, ¿qué afirmación refleja mejor el trade-off descrito en el texto?", options: [{ text: "Operar clústeres propios da máximo control técnico pero requiere perfiles especializados y mayor esfuerzo operativo continuo", isCorrect: true }, { text: "Los servicios gestionados garantizan siempre el menor coste posible, independientemente del uso real de la plataforma", isCorrect: false }, { text: "La infraestructura propia elimina cualquier necesidad de monitorización o de procesos de actualización planificados", isCorrect: false }, { text: "Los servicios gestionados impiden cumplir SLOs estrictos porque no permiten configurar ninguna opción avanzada", isCorrect: false }] , explanation: "Clúster propio = ser mecánico de tu coche. Todo a tu gusto, pero si se rompe lo arreglas tú. Gestionado = taxi, más fácil pero menos control (y a veces más caro)." },
  { question: "En la preparación de una matriz de decisión para elegir arquitectura y herramientas, ¿qué enfoque conecta mejor con costes y calidad de servicio?", options: [{ text: "Comparar únicamente el número de funcionalidades de cada herramienta, ignorando latencia, volumen, reprocesado y complejidad operativa", isCorrect: false }, { text: "Valorar solo la popularidad de las tecnologías en encuestas externas, asumiendo que lo más usado será siempre suficiente", isCorrect: false }, { text: "Incluir criterios como latencia aceptable, volumen, reprocesado, calidad exigida, coste estimado y complejidad operativa", isCorrect: true }, { text: "Escoger de antemano una combinación concreta de herramientas y rellenar después la matriz para justificar la decisión tomada", isCorrect: false }] , explanation: "Matriz de decisión madura = evalúa lo que importa a producción (TCO, latencia, soporte, reprocesado), no el checklist de features de marketing de la herramienta." },
  { question: "En una arquitectura donde varios microservicios producen eventos y múltiples sistemas analíticos los consumen, el beneficio clave de introducir Kafka frente a integraciones directas es que...", options: [{ text: "Centraliza el almacenamiento definitivo de datos históricos sustituyendo al data lake corporativo completo", isCorrect: false }, { text: "Desacopla productores y consumidores mediante topics ordenados, permitiendo reprocesar eventos desde puntos anteriores", isCorrect: true }, { text: "Garantiza automáticamente el entrenamiento continuo de modelos de machine learning sin necesidad de motores de cálculo adicionales", isCorrect: false }, { text: "Elimina la necesidad de gestionar particiones y replicación porque delega esas tareas por completo en la base de datos origen", isCorrect: false }] , explanation: "Kafka = buzón central. El microservicio deja la carta y se olvida. El data lake la coge cuando puede. Además, puedes volver atrás y releerla si hubo fallo." },
  { question: "Una empresa dice necesitar “tiempo real” pero acepta latencias de entre 10 y 30 segundos para sus dashboards; ya usa Kafka para ingesta. El motor más razonable para implementar el procesamiento continuo es...", options: [{ text: "Un clúster Flink dedicado a baja latencia, aun cuando la ventana de segundos no lo exige claramente", isCorrect: false }, { text: "Un data warehouse analítico clásico que consulte directamente la base de datos transaccional cada pocos segundos", isCorrect: false }, { text: "Spark en modo batch puro lanzando trabajos manuales cada vez que se quieran refrescar los informes", isCorrect: false }, { text: "Spark Structured Streaming leyendo de topics Kafka y generando agregados con microbatches frecuentes", isCorrect: true }] , explanation: "10-30s latencia = terreno ideal para micro-batch (Spark). Flink (latencia ms) es over-engineering aquí. Batch puro (horas) no llega. Spark S.S. encaja perfecto." },
  { question: "Una organización quiere reemplazar un conjunto de jobs nocturnos sobre grandes CSV en S3 por algo más robusto; la latencia de horas sigue siendo aceptable y no hay requisitos de streaming. La elección más sensata es...", options: [{ text: "Utilizar Spark para procesar en batch los ficheros históricos y generar informes diarios sobre el data lake", isCorrect: true }, { text: "Introducir Kafka como pieza central aunque todos los datos provengan de cargas nocturnas ya consolidadas", isCorrect: false }, { text: "Desplegar Flink con jobs de streaming permanentes sobrearchivosque se actualizan únicamente una vez al día", isCorrect: false }, { text: "Sustituir S3 por una cola de mensajes ligera y mantener los scripts secuenciales que ya existen en producción", isCorrect: false }] , explanation: "CSV nocturno + latencia horas aceptable = Batch tradicional (Spark). Meter Kafka o Flink aquí es añadir complejidad sin ningún beneficio para el negocio." },
  { question: "En un caso de fraude bancario donde se requiere reaccionar en cientos de milisegundos y mantener estado complejo por tarjeta a lo largo del tiempo, la opción más alineada con el problema es...", options: [{ text: "Usar exclusivamente Kafka con múltiples topics, implementando toda la lógica de correlación en los productores de eventos", isCorrect: false }, { text: "Montar Spark Structured Streaming en microbatch con ventanas amplias, aceptando una latencia de varios segundos garantizada", isCorrect: false }, { text: "Diseñar jobs de Flink con estado repartido, ventanas temporales y checkpoints integrados con Kafka como fuente", isCorrect: true }, { text: "Lanzar procesos batch diarios sobre el histórico para etiquetar operaciones sospechosas y avisar con retraso controlado", isCorrect: false }] , explanation: "Milisegundos + estado complejo (fraude tarjetas) = Flink. Su gestión nativa del estado distribuido es exactamente para este tipo de casos extremos." },
  { question: "En relación con el modelo de tiempo en sistemas de streaming, ¿qué ventaja concreta aporta que Flink trabaje con tiempo de evento frente a usar solo tiempo de procesamiento?", options: [{ text: "Permitir que los jobs se detengan y reanuden manualmente sin afectar a la posición de lectura en Kafka", isCorrect: false }, { text: "Manejar correctamente eventos atrasados o desordenados, evaluando ventanas según el timestamp real de los datos", isCorrect: true }, { text: "Forzar que todos los productores usen el mismo reloj de sistema, evitando cualquier diferencia de sincronización en origen", isCorrect: false }, { text: "Garantizar que la latencia percibida por el usuario final sea constante, independientemente de la carga del clúster", isCorrect: false }] , explanation: "Tiempo de evento = la hora a la que pasó, no a la que llegó al servidor. Permite ordenar datos que llegan tarde (late arrival) en la ventana correcta." },
  { question: "Una organización con poca experiencia operando clústeres distribuidos quiere empezar “con algo de Big Data” para informes y casos de uso aún poco definidos, priorizando simplicidad operativa. ¿Qué enfoque encaja mejor con esa situación?", options: [{ text: "Desplegar Kafka, Spark y Flink desde el principio para evitar futuras migraciones, aunque solo haya informes batch", isCorrect: false }, { text: "Configurar un clúster Flink complejo para procesar streams que aún no existen, dejando Kafka y Spark para más adelante", isCorrect: false }, { text: "Adoptar Kafka como única pieza central, sustituyendo directamente cualquier proceso batch sobre el lake ya existente", isCorrect: false }, { text: "Empezar por un motor tipo Spark o un data warehouse gestionado para procesar lotes y posponer el streaming avanzado", isCorrect: true }] , explanation: "Poca experiencia + requerimientos vagos = empieza simple (Data Warehouse / Batch Spark). Si metes Flink+Kafka el día 1, el equipo colapsará bajo el peso operativo." },
  { question: "Respecto a la relación entre Kafka y el reprocesado de datos históricos, ¿qué afirmación refleja mejor el papel de Kafka en una arquitectura de eventos?", options: [{ text: "Kafka actúa como log retenido por tiempo, permitiendo que nuevos consumidores “rebobinen” y lean desde offsets anteriores", isCorrect: true }, { text: "Kafka borra inmediatamente los mensajes en cuanto se consumen, evitando que se puedan leer más de una vez por sistema", isCorrect: false }, { text: "Kafka replica estados de operadores de streaming, sustituyendo la necesidad de checkpoints en motores como Flink", isCorrect: false }, { text: "Kafka mantiene una única copia global de cada evento, impidiendo la existencia de particiones para mejorar el rendimiento", isCorrect: false }] , explanation: "Kafka guarda los eventos unos días (retención). Si pones una versión nueva de tu consumidor, puede leer desde el pasado (rebobinar) y regenerar los datos." },
  { question: "Acerca de la latencia y la lógica de procesamiento, ¿qué diferencia conceptual ayuda a decidir entre Spark Structured Streaming y Flink en un proyecto nuevo?", options: [{ text: "Spark Structured Streaming obliga a programar cada transformación en bajo nivel, mientras que Flink solo admite SQL declarativo avanzado", isCorrect: false }, { text: "Spark Structured Streaming se centra en eventos individuales, y Flink está optimizado exclusivamente para grandes lotes estáticos", isCorrect: false }, { text: "Spark Structured Streaming suele ser adecuado para microbatches de segundos, mientras Flink destaca en streaming continuo de muy baja latencia", isCorrect: true }, { text: "Spark Structured Streaming garantiza exactly-once sin configuración adicional, y Flink solo ofrece procesamiento best-effort sin consistencia", isCorrect: false }] , explanation: "Diferencia base: Spark junta eventos en saquitos (micro-batch) de segundos. Flink procesa gota a gota continuo (ms). Elige según la prisa." },
  { question: "¿Por qué la estrategia de “meter Kafka, Spark y Flink por si acaso” suele ser problemática cuando se arranca una plataforma Big Data?", options: [{ text: "Porque el uso combinado de las tres tecnologías impide cumplir la normativa de protección de datos en la mayoría de sectores", isCorrect: false }, { text: "Porque introduce complejidad operativa y cognitiva innecesaria si los casos de uso no requieren realmente todas esas piezas", isCorrect: true }, { text: "Porque hace imposible integrar fuentes de datos relacionales tradicionales, que solo pueden conectarse a un único motor", isCorrect: false }, { text: "Porque obliga a renunciar a cualquier servicio gestionado en la nube y requiere siempre clústeres on-premises dedicados", isCorrect: false }] , explanation: "Complejidad cognitiva = al equipo le explota la cabeza. Tienen que aprender, monitorear y actualizar 3 sistemas enormes en vez de 1. Si no hace falta, no lo metas." },
  { question: "Al valorar qué sistema introducir primero, el texto insiste en tener en cuenta no solo requisitos técnicos sino también el equipo. ¿Qué criterio ligado al equipo resulta determinante según esa perspectiva?", options: [{ text: "Priorizar la herramienta con más contribuciones en redes sociales, aunque nadie del equipo tenga experiencia previa real", isCorrect: false }, { text: "Elegir siempre el motor más reciente del mercado, aun si introduce un paradigma totalmente desconocido para la organización", isCorrect: false }, { text: "Considerar únicamente el coste de licencias de software, sin analizar la curva de aprendizaje ni la carga operativa diaria", isCorrect: false }, { text: "Alinear la elección con las capacidades existentes del equipo y lo que se puede mantener razonablemente en producción", isCorrect: true }] , explanation: "Tecnología = personas. La mejor arquitectura en papel es basura si tu equipo no sabe arreglarla cuando se caiga a las 3 AM. Elige lo que puedan operar." },
];
